import React from "react";
import { Link } from "react-router-dom";

function Navbar() {
  return (
    <nav
      style={{
        background: "#0f172a",
        color: "white",
        padding: "16px 24px",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
      }}
    >
      <h2 style={{ margin: 0 }}>Football App</h2>

      <div style={{ display: "flex", gap: "18px" }}>
        <Link to="/" style={{ color: "white", textDecoration: "none" }}>
          Home
        </Link>
        <Link to="/fields" style={{ color: "white", textDecoration: "none" }}>
          Fields
        </Link>
        <Link
          to="/admin/bookings"
          style={{ color: "white", textDecoration: "none" }}
        >
          Admin Bookings
        </Link>
      </div>
    </nav>
  );
}

export default Navbar;
